      // \u83b7\u53d6\u8bf7\u6c42\u8def\u5f84\n        String requestURI = request.getRequestURI();\n        \n        // \u653e\u884c\u767b\u5f55\u9875\u9762\u548c\u9759\u6001\u8d44\u6e90\n        if (requestURI.contains("/login") || requestURI.contains("/static/")) {\n            return true;\n        }\n        \n        // \u68c0\u67e5\u7528\u6237\u662f\u5426\u767b\u5f55\n        Object user = request.getSession().getAttribute("user");\n        if (user == null) {\n            // \u672a\u767b\u5f55\uff0c\u91cd\u5b9a\u5411\u5230\u767b\u5f55\u9875\n            response.sendRedirect("/login");\n            return false;\n        }\n        \n        // \u5df2\u767b\u5f55\uff0c\u653e\u884c\n        return true;\n    }\n\n    /**\n     * \u8bf7\u6c42\u5904\u7406\u540e\u3001\u89c6\u56fe\u6e32\u67d3\u524d\u6267\u884c\n     */\n    @Override\n    public void postHandle(HttpServletRequest request, HttpServletResponse response, \n                          Object handler, ModelAndView modelAndView) throws Exception {\n        \n        // \u53ef\u4ee5\u5728ModelAndView\u4e2d\u6dfb\u52a0\u516c\u5171\u6570\u636e\n        if (modelAndView != null) {\n            modelAndView.addObject("currentTime", new java.util.Date());\n        }\n    }\n\n    /**\n     * \u8bf7\u6c42\u5904\u7406\u5b8c\u6210\u540e\u6267\u884c\uff08\u89c6\u56fe\u6e32\u67d3\u540e\uff09\n     */\n    @Override\n    public void afterCompletion(HttpServletRequest request, HttpServletResponse response, \n                               Object handler, Exception ex) throws Exception {\n        \n        // \u53ef\u4ee5\u8bb0\u5f55\u8bf7\u6c42\u8017\u65f6\u7b49\n        long startTime = (Long) request.getAttribute("startTime");\n        long endTime = System.currentTimeMillis();\n        System.out.println("\u8bf7\u6c42\u8017\u65f6\uff1a" + (endTime - startTime) + "ms");\n    }\n}\n'})}),"\n",(0,t.jsx)(e.p,{children:(0,t.jsx)(e.strong,{children:"\u914d\u7f6e\u62e6\u622a\u5668"})}),"\n",(0,t.jsx)(e.pre,{children:(0,